    ('criminal', 'criminal-procedure-code', 'პრაქტიკულ საქმეში მხარემ განაცხადა, რომ შემდეგი წესი უნდა გამოიყენოს: ამ კოდექსის მიზნებისათვის 2015 წლის 1 აპრილამდე სასამართლოს მიერ ქმედუუნაროდ ცნობილი პირის კანონიერ წარმომადგენლად ითვლება მისი მეურვე, სანამ ქმედუუნარო პირის ინდივიდუალური შეფასება. საქართველოს სისხლის სამართლის საპროცესო კოდექსის შესაბამისად, რომელი სამართლებრივი შეფასებაა სწორი?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 332⁴ ადგენს სწორედ ამ სამართლებრივ წესს.', 'საქართველოს სისხლის სამართლის საპროცესო კოდექსი', 'მუხლი 332⁴', '', '2026-06-29', false, 'მითითებული მიდგომა სწორია; ამ წესს ადგენს საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 332⁴.', 'ეს მიდგომა გამოიყენება მხოლოდ სასამართლოს სპეციალური ნებართვის შემთხვევაში.', 'ეს მიდგომა არ გამოიყენება სისხლის სამართალში და მხოლოდ სამოქალაქო დავას ეხება.', 'ეს მიდგომა მოქმედებს მხოლოდ მაშინ, თუ ბრალდებული წერილობით დაეთანხმება.', 'A'),
    ('criminal', 'criminal-procedure-code', 'პრაქტიკულ საქმეში მხარემ განაცხადა, რომ შემდეგი წესი უნდა გამოიყენოს: 2023 წლის 1 იანვრამდე პანდემიის ან/და საზოგადოებრივი ჯანმრთელობისთვის განსაკუთრებით საშიში ეპიდემიის გავრცელების საფრთხის არსებობის შემთხვევაში საქართველოს სისხლის სამართლის. საქართველოს სისხლის სამართლის საპროცესო კოდექსის შესაბამისად, რომელი სამართლებრივი შეფასებაა სწორი?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 332⁵ ადგენს სწორედ ამ სამართლებრივ წესს.', 'საქართველოს სისხლის სამართლის საპროცესო კოდექსი', 'მუხლი 332⁵', '', '2026-06-29', false, 'მითითებული მიდგომა სწორია; ამ წესს ადგენს საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 332⁵.', 'ეს მიდგომა გამოიყენება მხოლოდ სასამართლოს სპეციალური ნებართვის შემთხვევაში.', 'ეს მიდგომა არ გამოიყენება სისხლის სამართალში და მხოლოდ სამოქალაქო დავას ეხება.', 'ეს მიდგომა მოქმედებს მხოლოდ მაშინ, თუ ბრალდებული წერილობით დაეთანხმება.', 'A'),
    ('criminal', 'criminal-procedure-code', 'პრაქტიკულ საქმეში მხარემ განაცხადა, რომ შემდეგი წესი უნდა გამოიყენოს: ეს კოდექსი, გარდა 310-ე მუხლის „ე“ ქვეპუნქტისა, ამოქმედდეს 2010 წლის 1 ოქტომბრიდან. საქართველოს სისხლის სამართლის საპროცესო კოდექსის შესაბამისად, რომელი სამართლებრივი შეფასებაა სწორი?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 333 ადგენს სწორედ ამ სამართლებრივ წესს.', 'საქართველოს სისხლის სამართლის საპროცესო კოდექსი', 'მუხლი 333', '', '2026-06-29', false, 'ეს მიდგომა მოქმედებს მხოლოდ მაშინ, თუ ბრალდებული წერილობით დაეთანხმება.', 'მითითებული მიდგომა სწორია; ამ წესს ადგენს საქართველოს სისხლის სამართლის საპროცესო კოდექსის მუხლი 333.', 'ეს მიდგომა გამოიყენება მხოლოდ სასამართლოს სპეციალური ნებართვის შემთხვევაში.', 'ეს მიდგომა არ გამოიყენება სისხლის სამართალში და მხოლოდ სამოქალაქო დავას ეხება.', 'B')
  ) as s(category_slug, subcategory_slug, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, option_a, option_b, option_c, option_d, correct_option)
  loop
    select id into v_article_id
    from public.law_articles
    where law_id = v_law_id and article_number = r.law_article;

    insert into public.questions(
      category_id, subcategory_id, text, difficulty, explanation, law_name, law_article,
      source_url, law_version_date, needs_review, is_prime, is_published, verified_at,
      law_id, primary_law_article_id
    )
    values (
      v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation,
      r.law_name, r.law_article, nullif(r.source_url,''), r.law_version_date::date,
      false, r.is_prime, true, now(), v_law_id, v_article_id
    )
    returning id into v_question_id;

    insert into public.question_options(question_id, option_text, is_correct, sort_order) values
    (v_question_id, r.option_a, r.correct_option='A', 1),
    (v_question_id, r.option_b, r.correct_option='B', 2),
    (v_question_id, r.option_c, r.correct_option='C', 3),
    (v_question_id, r.option_d, r.correct_option='D', 4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update set is_primary=true;
  end loop;
end $$;
